{
  "shots": [
    {
      "shot_id": "SH01",
      "priority": "P0",
      "intent": "现实时间起点：田中健一刚离开银座酒店建筑正门，被午后阳光刺得眯眼，随后触到身上的深藏青色领带，作为前夜回忆的触发点。",
      "duration_sec": 5,
      "shot_type": "中近景",
      "movement": "固定机位，允许极轻微稳定推镜",
      "framing_focus": "午后的银座酒店建筑正门外，田中健一正脸站在入口门廊外侧，午后自然阳光照到脸上，他眯起眼睛，深藏青色领带贴在白衬衫与深灰西装前襟上。画面重点放在他的眯眼正脸、胸前领带与靠近西装口袋的手部。",
      "action_intent": "从首帧的正门外位置继续停稳，田中健一把双手插进西装口袋，右手指尖在口袋口附近轻触到1条佩戴在颈部并垂在前襟上的深藏青色领带尾端；动作微小克制，只完成领带触感触发回忆这一件事。",
      "emotion_intent": "阳光刺眼后的短暂不适转为克制的不安，眼神收紧，像被领带触感拉回昨夜。",
      "scene_id": "EP02_GINZA_HOTEL_ENTRANCE_AFTERNOON",
      "scene_name": "银座酒店大门外午后",
      "time_of_day": "午后",
      "primary_light_source": "午后自然阳光",
      "dialogue": [],
      "narration": [],
      "subtitle": [],
      "positive_core": "午后的银座案发酒店建筑正门外，田中健一正脸站在入口门廊外侧，午后自然阳光照到他脸上，他眯起眼睛，胸前1条深藏青色低光泽织纹领带清楚可见。竖屏9:16写实电影感，中近景，低饱和真实光影，酒店正门玻璃与金属门框在他身后，街边强光从前方偏侧照来，秋日凉风轻拂他的西装衣摆；他沉默停稳，把双手插进口袋，右手指尖轻触到贴近西装前襟的领带尾端，嘴部闭合，神情克制不安。人物衣着完整，保持日常社交距离，朴素克制呈现。",
      "resolved_costume": {
        "田中健一": {
          "character_id": "KENICHI_MAIN",
          "name": "田中健一",
          "costume": "深灰色通勤西装外套、白色棉质衬衫、深藏青色领带、深色西裤、黑色皮鞋；人物衣着完整，保持日常社交距离，朴素克制呈现",
          "source": "episode_costume_contract",
          "is_canonical": false,
          "costume_id": "KENICHI_EP02_BUSINESS_SUIT_WITH_TIE",
          "applies_to_shots": [
            "SH01"
          ],
          "costume_change_event": "",
          "evidence": "1) TARGET_FACTS明确本shot关键服装道具为深色领带；2) EPISODE_COSTUME_CONTRACT覆盖SH01并指定深灰通勤西装、白衬衫、深藏青领带、深色西裤、黑色皮鞋；3) 本集无上一镜可继承；4) 最终采用本集服装合同，而非角色基础服装单独覆盖。"
        }
      },
      "first_frame_contract": {
        "location": "银座案发酒店建筑正门外入口门廊侧，午后",
        "visual_center": "田中健一被午后自然阳光照到而眯起的正脸，以及胸前清楚可见的深藏青色领带",
        "composition_method": {
          "template_id": "single",
          "template_name": "单人稳定中近景",
          "source": "composition.md",
          "rationale": "首帧只有田中健一1名可见人物，本镜头任务是动作触发回忆，需要单人正脸和领带同时清楚。"
        },
        "visible_characters": [
          "田中健一"
        ],
        "character_positions": {
          "田中健一": "画面中央略偏上，站在酒店正门外侧，身体面向午后街边强光，胸前领带位于画面中部"
        },
        "character_face_visibility": {
          "田中健一": "正脸可见，五官和眼神清楚，因午后强光眯起眼睛，嘴部闭合"
        },
        "key_props": [
          "KENICHI_TIE_EP02",
          "酒店建筑正门"
        ],
        "speaking_state": "田中健一沉默，画面内外没有人物说话，可保留午后街面环境声与轻风声。",
        "camera_motion_allowed": "固定机位，允许极轻微稳定推镜",
        "costume_modifiers": {
          "田中健一": "深灰色通勤西装外套、白色棉质衬衫、深藏青色领带、深色西裤、黑色皮鞋"
        }
      },
      "dialogue_blocking": {
        "active_speaker": null,
        "first_speaker": null,
        "speaker_visual_priority": "center_face",
        "silent_visible_characters": [
          "田中健一"
        ],
