        "shot_task": "action",
        "risk_level": "low",
        "risk_notes": "单人、单地点、无对白、无电话；主要风险是领带触摸位置需保持为同一条佩戴在颈部并垂在前襟上的领带，动作控制为轻触尾端。",
        "prop_library": {
          "KENICHI_TIE_EP02": {
            "display_name": "健一的深色领带",
            "count": "1条",
            "size": "长度约145厘米，最宽处约7厘米",
            "color": "深藏青色",
            "material": "低光泽织纹丝质混纺",
            "structure": "长条领带，标准尖角尾端，系在白衬衫领口，结扣可被轻微拉松",
            "front_description": "",
            "back_description": "",
            "canonical_motion_policy": "本集保持同一条领带；现实段佩戴在健一颈部且尾端贴近西装前襟，前夜段可由彩花指尖缓慢拉松结扣，不出现替换。"
          }
        },
        "prop_contract": [
          {
            "prop_id": "KENICHI_TIE_EP02",
            "position": "本镜头首帧佩戴在田中健一颈部，深藏青色领带结位于白衬衫领口，尾端沿深灰西装前襟垂下并靠近右侧西装口袋口",
            "first_frame_visible": true,
            "motion_policy": "数量固定为1条；允许田中健一右手指尖在口袋口附近轻触领带尾端，领带保持佩戴状态，只产生很小幅度摆动",
            "controlled_by": "田中健一",
            "current_visible_side": "none",
            "orientation_to_camera": "none",
            "quantity_policy": "全镜头保持1条同一领带，不增加副本，不替换颜色、材质、尺寸和结构",
            "flip_policy": "not_applicable"
          }
        ],
        "phone_contract": null
      },
      "source_basis": "“田中健一走出酒店大门时，午后的阳光刺得他眯起眼睛……凉风拂过脸庞，带着一丝秋日的凉意……他停下脚步，双手插进口袋，指尖无意中触到那条领带。”"
    }
  ],
  "qa_report": [
    {
      "check": "shot count and identity",
      "result": "pass",
      "notes": "只生成SH01一个镜头，shots数组长度为1，shot_id为SH01，duration_sec按硬性要求填写为5。"
    },
    {
      "check": "semantic interview ground truth",
      "result": "pass",
      "notes": "首帧地点为银座酒店建筑正门外午后，唯一可见人物为田中健一；没有彩花、套房、电话、照片、对白和旁白。"
    },
    {
      "check": "TARGET_FACTS and TARGET_SPINE_ROW traceability",
      "result": "pass",
      "notes": "覆盖事实1：健一离开酒店大门外，被午后阳光刺得眯眼，停步触到深藏青色领带。TARGET_SPINE_ROW给出4秒，硬性要求指定duration_sec必须为5，本输出采用5秒。"
    },
    {
      "check": "I2V rule self-check",
      "result": "pass",
      "notes": "本镜头为单一action任务；无对白，lip_sync_policy为no_dialogue；首帧为单一稳定状态，单人正脸可见；动作仅为停稳和轻触领带。"
    },
    {
      "check": "prop consistency",
      "result": "pass",
      "notes": "使用TARGET_PROP_CATALOG中的KENICHI_TIE_EP02，数量、尺寸、颜色、材质、结构和运动策略与道具库一致；首帧明确可见。"
    },
    {
      "check": "costume continuity",
      "result": "pass",
      "notes": "田中健一服装来自EPISODE_COSTUME_CONTRACT覆盖SH01的本集服装合同；无上一镜继承需求，无换装事件。"
    },
    {
      "check": "conflict report",
      "result": "pass",
      "notes": "TARGET_FACTS与SEMANTIC_INTERVIEW_GROUND_TRUTH在人物可见性、地点、声音和关键动作上无实质冲突；领带位置存在中等歧义，按TARGET_PROP_CATALOG确定为佩戴在颈部且尾端贴近前襟。"
    }
  ]
